package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testWithRecordSeparatorString() throws Exception {
        // Arrange
        CSVFormat original = CSVFormat.DEFAULT;
        String newRecordSeparator = "\n";

        // Act
        CSVFormat updated = original.withRecordSeparator(newRecordSeparator);

        // Assert
        assertNotNull(updated);
        assertNotSame(original, updated);
        assertEquals(newRecordSeparator, updated.getRecordSeparator());

        // Original remains unchanged
        assertEquals("\r\n", original.getRecordSeparator());

        // Test with null recordSeparator
        CSVFormat nullRecordSeparatorFormat = original.withRecordSeparator(null);
        assertNull(nullRecordSeparatorFormat.getRecordSeparator());

        // Reflection test: invoke private method withRecordSeparator to verify fields set correctly
        Method withRecordSeparatorMethod = CSVFormat.class.getDeclaredMethod("withRecordSeparator", String.class);
        withRecordSeparatorMethod.setAccessible(true);
        CSVFormat reflectedFormat = (CSVFormat) withRecordSeparatorMethod.invoke(original, "RS");
        assertEquals("RS", reflectedFormat.getRecordSeparator());
    }
}
